changeSet.sql:
ALTER TABLE nexus.catalog_documents DROP COLUMN fts_vector;
ALTER TABLE nexus.catalog_documents
    ADD COLUMN fts_vector tsvector GENERATED ALWAYS AS (
        to_tsvector('english', coalesce(title, ''))
        || to_tsvector('simple',  coalesce(author, ''))
        || to_tsvector('simple',  coalesce(corpus, ''))
        || to_tsvector('simple',  coalesce(file_path, ''))
        || to_tsvector('simple',
               translate(coalesce(title, '') || ' ' || coalesce(file_path, ''),
                         '/.-_', '    '))
    ) STORED;
CREATE INDEX idx_catalog_documents_fts
    ON nexus.catalog_documents USING GIN (fts_vector);

